<?php
namespace App\Services;use App\Models\TopupOrder;use App\Services\Provider\ProviderManager;class OrderService{public function processProvider(TopupOrder $order):TopupOrder{$order->load('provider','package');$result=app(ProviderManager::class)->driver($order->provider)->submitOrder($order);$order->update(['order_status'=>$result['success']?'completed':'failed','provider_status'=>$result['success']?'success':'failed','provider_order_id'=>$result['provider_order_id']??null,'provider_response'=>$result['raw']??null,'message'=>$result['message']??($result['success']?'Completed':'Provider failed')]);return $order;}}
